// ==========================================
// 1. RÉCUPÉRATION DES DONNÉES
// ==========================================
const clientData = $('When Executed by Another Workflow').item.json || {};
const params = $('Parametres_Globaux1').item.json.fields || {};

const matricesItems = $('Matrices').all() || [];
const matrices = matricesItems.map(item => item.json.fields || {});

const forfaitsItems = $('Forfaits_KM').all() || [];
const forfaits = forfaitsItems.map(item => item.json.fields || {}); 

// Date pivot pour tester l'anticipation (gérée dynamiquement)
const today = params.TODAY ? new Date(params.TODAY) : new Date();

// ==========================================
// 2. LE MOTEUR D'ANALYSE D'INTERVALLES
// ==========================================
function verifierCondition(valeur, conditionStr) {
    if (!conditionStr) return false;
    conditionStr = String(conditionStr).trim();
    if (conditionStr.startsWith('<=')) return valeur <= parseFloat(conditionStr.replace('<=', ''));
    if (conditionStr.startsWith('<')) return valeur < parseFloat(conditionStr.replace('<', ''));
    if (conditionStr.startsWith('>=')) return valeur >= parseFloat(conditionStr.replace('>=', ''));
    if (conditionStr.startsWith('>')) return valeur > parseFloat(conditionStr.replace('>', ''));
    return false;
}

function matchPalier(valeur, regleAirtable) {
    if (!regleAirtable) return false;
    const parties = String(regleAirtable).split(' et ').map(s => s.trim());
    if (parties.length === 2) {
        return verifierCondition(valeur, parties[0]) && verifierCondition(valeur, parties[1]);
    }
    return verifierCondition(valeur, regleAirtable);
}

// ==========================================
// 3. ANALYSE DU TRAJET ET DES DATES
// ==========================================
const distSource = $('Calcul_Distane_Metre').item.json;
let distMetres = 0;
if (distSource && distSource.routes && distSource.routes[0] && distSource.routes[0].legs[0]) {
    distMetres = distSource.routes[0].legs[0].distance;
}
let distanceUnTrajetKm = distMetres / 1000;

let multiplicateurTrajet = (clientData.Type_Trajet === "Aller-Retour") ? 2 : 1;
let distanceTotaleKm = distanceUnTrajetKm * multiplicateurTrajet;

let nbNuits = 0, nbJours = 1;
if (clientData.Date_Depart && clientData.Date_Retour) {
    const d1 = new Date(clientData.Date_Depart);
    const d2 = new Date(clientData.Date_Retour);
    const diffDays = Math.ceil((d2 - d1) / (1000 * 60 * 60 * 24));
    if (diffDays > 0) {
        nbNuits = diffDays;
        nbJours = diffDays + 1;
    }
}

// ==========================================
// 4. IDENTIFICATION DES COEFFICIENTS (MATRICES)
// ==========================================
const pax = clientData.Nombre_Passagers || 0;
const matCapacite = matrices.find(m => m.Type_Critere === 'Capacite' && matchPalier(pax, m.Valeur_Cle));
const coefCapacite = matCapacite ? Number(matCapacite.Coefficient) : 0;
const idCapacite = matCapacite ? matCapacite.ID_Critere : "AUCUN";

const dDepart = new Date(clientData.Date_Depart);
const joursAnticipation = Math.floor((dDepart - today) / (1000 * 60 * 60 * 24));
const matAnticipation = matrices.find(m => m.Type_Critere === 'Anticipation' && matchPalier(joursAnticipation, m.Valeur_Cle));
const coefAnticipation = matAnticipation ? Number(matAnticipation.Coefficient) : 0;
const idAnticipation = matAnticipation ? matAnticipation.ID_Critere : "AUCUN";

const moisNoms = ["janvier", "fevrier", "mars", "avril", "mai", "juin", "juillet", "aout", "septembre", "octobre", "novembre", "decembre"];
const moisDepart = (dDepart && !isNaN(dDepart)) ? moisNoms[dDepart.getMonth()] : "inconnu";
const matSaison = matrices.find(m => m.Type_Critere === 'Saisonnalite' && String(m.Valeur_Cle).toLowerCase().includes(moisDepart));
const coefSaison = matSaison ? Number(matSaison.Coefficient) : 0;
const idSaison = matSaison ? matSaison.ID_Critere : "AUCUN";

const coefGlobalMatrices = coefCapacite + coefAnticipation + coefSaison;

// ==========================================
// 5. CALCUL DES COÛTS SECS (PARAMÈTRES DYNAMIQUES)
// ==========================================
let coutTransportSec = 0;
let detailsForfait = "";

// Variables strictement issues de Airtable
const SEUIL = Number(params.SEUIL_DIST_FORFAIT);
const prixKmHorsForfait = Number(params.PRIX_KM_HORS_FORFAIT);

if (distanceTotaleKm > 0 && distanceTotaleKm <= SEUIL) {
    const forfaitTrouve = forfaits.find(f => matchPalier(distanceTotaleKm, f.Palier_KM));

    if (forfaitTrouve && forfaitTrouve.Tarif_Forfait_HT) {
        coutTransportSec = Number(forfaitTrouve.Tarif_Forfait_HT);
        detailsForfait = `Forfait appliqué: Règle [ ${forfaitTrouve.Palier_KM} ] (pour ${distanceTotaleKm.toFixed(2)} km réels)`;
    } else {
        coutTransportSec = distanceTotaleKm * prixKmHorsForfait;
        detailsForfait = `Erreur: Aucun palier valide pour ${distanceTotaleKm.toFixed(2)} km - Tarif au KM réel activé`;
    }
} else {
    coutTransportSec = distanceTotaleKm * prixKmHorsForfait;
    detailsForfait = `Tarif au KM réel activé (${distanceTotaleKm.toFixed(2)} km > ${SEUIL} km)`;
}

const prixNuitChauffeur = Number(params.PRIX_NUIT_CHAUFFEUR);
const prixGuideJour = Number(params.PRIX_GUIDE_JOUR);

let coutNuites = nbNuits * prixNuitChauffeur;
let coutGuide = (clientData.Option_Guide === "Oui" || clientData.Option_Guide === "true" || clientData.Option_Guide === true) ? nbJours * prixGuideJour : 0;

let sousTotalBrut = coutTransportSec + coutNuites + coutGuide;

// ==========================================
// 6. APPLICATION FINALE (MARGE & TVA DYNAMIQUES)
// ==========================================
let coutApresMatrices = sousTotalBrut * (1 + coefGlobalMatrices);

const margeCommerciale = Number(params.MARGE_COMMERCIALE);
let prixDeVenteHT = coutApresMatrices / (1 - margeCommerciale);

const tva = Number(params.TVA_TRANSPORT);
let prixDeVenteTTC = prixDeVenteHT * (1 + tva);
let montantTVA = prixDeVenteTTC - prixDeVenteHT;

// ==========================================
// 7. RENDU FINAL
// ==========================================
return {
    json: {
        ...clientData,
        Prix_HT: (Math.round(prixDeVenteHT * 100) / 100).toFixed(2),
        Prix_TTC: (Math.round(prixDeVenteTTC * 100) / 100).toFixed(2),
        Distance_Totale_KM: distanceTotaleKm.toFixed(2),

        Details_Calcul: {
            Type_Tarification: detailsForfait,
            Base_Trajet: {
                Aller_Simple_KM: distanceUnTrajetKm.toFixed(2),
                Distance_Facturee_KM: distanceTotaleKm.toFixed(2)
            },
            Planning: {
                Jours_Mobilises: nbJours,
                Nuits_Chauffeur: nbNuits
            },
            Matrices_Appliquees: {
                Capacite: { Règle: idCapacite, Valeur: pax + " pax", Coef: (coefCapacite * 100) + "%" },
                Saisonnalite: { Règle: idSaison, Valeur: "Mois de " + moisDepart, Coef: (coefSaison * 100) + "%" },
                Anticipation: { Règle: idAnticipation, Valeur: joursAnticipation + " jours", Coef: (coefAnticipation * 100) + "%" },
                Impact_Total_Coef: (coefGlobalMatrices * 100) + "%"
            },
            Couts_Transparents: {
                Transport_Sec: coutTransportSec.toFixed(2) + " €",
                Frais_Nuites: coutNuites.toFixed(2) + " €",
                Frais_Guide: coutGuide.toFixed(2) + " €",
                Sous_Total_Avant_Coef: sousTotalBrut.toFixed(2) + " €",
                Cout_Revient_Apres_Coef: coutApresMatrices.toFixed(2) + " €"
            },
            Taxes_Et_Marge: {
                Marge_Commerciale: (margeCommerciale * 100) + "%",
                Montant_Marge: (prixDeVenteHT - coutApresMatrices).toFixed(2) + " €",
                TVA_Appliquee: (tva * 100) + "%",
                Montant_TVA: montantTVA.toFixed(2) + " €"
            }
        }
    }
};
